1	/**
2	 * Auth configuration — sourced at RUNTIME, not build time (ADR 0028).
3	 *
4	 * The container serves `/config.js` (rendered from env by nginx at startup) which
5	 * sets `window.__DATAQ_CONFIG__` before the app bundle runs. That means one
6	 * generic image with nothing baked in — no cloud, no secret, no auth-bypass.
7	 * When no such global is present — `pnpm dev`, and the static/SWA build until the
8	 * ADR-0028 cutover — we fall back to the build-time `VITE_*` env (bypass there
9	 * stays DEV-gated, so a production static bundle can't enable it).
10	 *
11	 * The injected contract is provider-neutral (`DATAQ_AUTH_*`): `mode` + a standard
12	 * OIDC-shaped `authority` / `clientId` / `apiScope`. Azure is one populated shape
13	 * (`authority = https://login.microsoftonline.com/<tenant>/v2.0`); no `AZURE` in
14	 * the contract.
15	 *
16	 * Mode is computed once at module load:
17	 * - 'real'         — `mode:'oidc'` with authority + clientId present. The auth
18	 *                    client (MSAL today; a generic OIDC client next — #504) drives
19	 *                    redirect-flow login + token acquisition.
20	 * - 'dev_bypass'   — ONLY when `mode:'bypass'` is explicitly set. Fail-closed:
21	 *                    never inferred from missing config. Renders a fixed dev user.
22	 * - 'unconfigured' — anything else. AuthGate shows a setup-needed banner.
23	 */
24	
25	export type AuthMode = 'real' | 'dev_bypass' | 'unconfigured';
26	
27	/** The runtime auth contract injected via `window.__DATAQ_CONFIG__.auth`. */
28	export interface DataqAuthConfig {
29	  /** 'bypass' = no IdP (local/eval); 'oidc' = real sign-in. Absent → unconfigured. */
30	  mode?: 'bypass' | 'oidc';
31	  /** OIDC issuer/authority URL (e.g. https://login.microsoftonline.com/<tenant>/v2.0). */
32	  authority?: string;
33	  /** The public SPA client id registered with the IdP. */
34	  clientId?: string;
35	  /** Full scope string requested for the API access token (Azure: api://<api-client-id>/<scope>). */
36	  apiScope?: string;
37	}
38	
39	declare global {
40	  interface Window {
41	    __DATAQ_CONFIG__?: { auth?: DataqAuthConfig };
42	  }
43	}
44	
45	/**
46	 * Build-time fallback for `pnpm dev` (no injected /config.js). Maps the legacy
47	 * VITE_* Azure vars onto the generic contract so local dev is unchanged. Bypass
48	 * still requires the explicit VITE_AUTH_DEV_BYPASS=true opt-in.
49	 */
50	function fromBuildEnv(): DataqAuthConfig {
51	  const tenantId = import.meta.env.VITE_AZURE_TENANT_ID;
52	  const clientId = import.meta.env.VITE_AZURE_SPA_CLIENT_ID;
53	  const apiClientId = import.meta.env.VITE_AZURE_API_CLIENT_ID;
54	  const scope = import.meta.env.VITE_AZURE_API_SCOPE || 'user_impersonation';
55	  // Belt-and-suspenders: bypass in the build-env fallback stays gated on a DEV
56	  // build, so a production static bundle (e.g. the SWA deploy, which serves this
57	  // fallback path — the /config.js stub sets no global) can never enable auth
58	  // bypass even if VITE_AUTH_DEV_BYPASS=true were baked in. The image path never
59	  // reaches here (nginx injects window.__DATAQ_CONFIG__).
60	  const bypass = import.meta.env.DEV && import.meta.env.VITE_AUTH_DEV_BYPASS === 'true';
61	  return {
62	    mode: bypass ? 'bypass' : tenantId && clientId ? 'oidc' : undefined,
63	    authority: tenantId ? `https://login.microsoftonline.com/${tenantId}/v2.0` : undefined,
64	    clientId: clientId || undefined,
65	    apiScope: apiClientId ? `api://${apiClientId}/${scope}` : undefined,
66	  };
67	}
68	
69	// The injected runtime config wins; the build-time env is the dev-only fallback
70	// used only when no /config.js was served (i.e. `pnpm dev`).
71	const injected = typeof window !== 'undefined' ? window.__DATAQ_CONFIG__?.auth : undefined;
72	const cfg: DataqAuthConfig = injected ?? fromBuildEnv();
73	
74	export const authConfig = {
75	  authority: cfg.authority,
76	  clientId: cfg.clientId,
77	  apiScope: cfg.apiScope,
78	} as const;
79	
80	export const authMode: AuthMode = (() => {
81	  // Fail-closed: bypass ONLY on the explicit flag, never inferred.
82	  if (cfg.mode === 'bypass') return 'dev_bypass';
83	  if (cfg.authority && cfg.clientId) return 'real';
84	  return 'unconfigured';
85	})();
86	
87	export const DEV_USER = {
88	  name: 'Dev Bypass User',
89	  username: 'dev-bypass@dataq.local',
90	  homeAccountId: 'dev-bypass',
91	  isDev: true as const,
92	};
